package controllers

import javax.inject._
import play.api.mvc._
import models.Order
import repositories.OrderRepository

@Singleton
class OrderController @Inject()(val controllerComponents: ControllerComponents, orderRepository: OrderRepository) extends BaseController {

  def getOrderById(id: Long): Action[AnyContent] = Action.async {
